import { CompositeDisposable } from 'atom';

const PROTOCOL = 'md-wysiwyg://';

module.exports = {
  subscriptions: null,

  activate(state) {
    console.log('md-wysiwyg: activate called');
    this.subscriptions = new CompositeDisposable();

    this.subscriptions.add(atom.commands.add('atom-workspace', {
      'md-wysiwyg:open': () => {
        console.log('md-wysiwyg: open command triggered');
        atom.notifications.addInfo('md-wysiwyg: hello!');
      }
    }));

    this.subscriptions.add(
      atom.workspace.addOpener((uri) => {
        console.log('md-wysiwyg: opener called with', uri);
        if (uri.startsWith(PROTOCOL)) {
          const filePath = uri.replace(PROTOCOL, '');
          return new TestPaneItem(filePath);
        }
      })
    );

    console.log('md-wysiwyg: activated successfully');
  },

  deactivate() {
    this.subscriptions.dispose();
  },

  serialize() {
    return {};
  }
};

class TestPaneItem {
  constructor(filePath) {
    this.filePath = filePath;
    this.element = document.createElement('div');
    this.element.textContent = 'WYSIWYG placeholder: ' + filePath;
    this.element.style.padding = '20px';
  }
  getTitle() { return 'WYSIWYG: ' + this.filePath; }
  getURI() { return PROTOCOL + this.filePath; }
  getPath() { return this.filePath; }
  getElement() { return this.element; }
  serialize() { return { filePath: this.filePath, deserializer: 'md-wysiwyg' }; }
  isModified() { return false; }
  onDidChangeModified() { return { dispose() {} }; }
  onDidChangeTitle() { return { dispose() {} }; }
  onDidDestroy() { return { dispose() {} }; }
  destroy() { this.element.remove(); }
}
